146	  it.todo("should share the cap across successive claims and reduce payout to the remaining cap");
147	
148	  // Rounding down in MHPCO's favor
149	  it.todo("should round the final payout down (350.5 G becomes 350 G)");
150	
151	  // Error cases
152	  it.todo("should reject a claim whose damage entry references an item not in the policy");
153	  it.todo("should reject a claim with more damage entries of a type than the policy covers");
154	  it.todo("should reject a claim with a negative damage amount");
155	});
